Функция ПолучитьСальдоПоСчету(СсылкаНаСчет)

    Запрос = Новый Запрос;
    Запрос.Текст =
        "ВЫБРАТЬ
            СУММА(ВЫРАЗИТЬ(
                ? * Хозрасчетный.Сумма,
                ТипЧисла(15, 2))) КАК Сальдо
        ИЗ
            РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
        ГДЕ
            Хозрасчетный.СчётДт В ИЕРАРХИИ(&Счет)
            ИЛИ Хозрасчетный.СчётКт В ИЕРАРХИИ(&Счет)";

    Если СсылкаНаСчет.Вид = Перечисление.ВидыСчетов.Пассивный Тогда
        // Для пассивных счетов считаем кредитовое сальдо
        Запрос.УстановитьПараметр("?", -1); 
    Иначе
        // Для активных и активно-пассивных счетов считаем дебетовое сальдо
        Запрос.УстановитьПараметр("?", 1);  
    КонецЕсли;   

    Запрос.УстановитьПараметр("Счет", СсылкаНаСчет);

    РезультатЗапроса = Запрос.Выполнить();
    ВыборкаДетальныеЗаписи = РезультатЗапроса.Выбрать();

    Если ВыборкаДетальныеЗаписи.Следующий() Тогда
        Возврат ВыборкаДетальныеЗаписи.Сальдо;
    Иначе
        Возврат 0;
    КонецЕсли;

КонецФункции
